INSERT INTO journal_entries (record_id, project, category, content, tags, createdat, local_project_id) VALUES
('d1tp1_journal_001', 'recgdpwEI5hF07bUZ', 'perceptions', 'The team is beginning to see research evidence as an operating model rather than a set of documents. People trust findings more when they can see where an observation came from, what is still uncertain and which decision it was meant to support.', '["evidence-readiness","confidence","decision-support"]', '2026-06-03T09:15:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_002', 'recgdpwEI5hF07bUZ', 'procedures', 'The weekly intake meeting now checks every new research request for the decision it supports, the evidence already available, the recruitment route and any delivery deadline before work is accepted.', '["triage","request-intake","planning"]', '2026-06-03T14:40:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_003', 'recgdpwEI5hF07bUZ', 'decisions', 'We decided to keep operations tracking separate from qualitative synthesis. Recruitment status and scheduling need to stay visible, but coding and memo writing should remain in the analysis space with links back to decisions.', '["decision-trace","operations","synthesis"]', '2026-06-04T10:05:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_004', 'recgdpwEI5hF07bUZ', 'introspections', 'The strongest value of the platform may be that it slows down the right decisions while making routine research administration easier to manage. That slower pace is uncomfortable, but it is also where the quality improves.', '["reflection","governance","decision-quality"]', '2026-06-04T16:20:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_005', 'recgdpwEI5hF07bUZ', 'procedures', 'Recruitment planning exposed a gap between the participant access needs recorded by delivery teams and the practical adjustments researchers need before a session. We added a check for access needs before diary invitations are sent.', '["recruitment","access-needs","participant-support"]', '2026-06-05T09:30:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_006', 'recgdpwEI5hF07bUZ', 'perceptions', 'Several researchers described losing the thread when they moved between the project dashboard, notes, spreadsheets and mural boards. The issue is not only tool count; it is the mental effort of rebuilding context every time.', '["context-rebuilding","tool-switching","researcher-workload"]', '2026-06-05T13:10:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_007', 'recgdpwEI5hF07bUZ', 'introspections', 'I noticed that I was treating missing provenance as a delivery inconvenience rather than an analytical risk. If we cannot tell who contributed an insight or when it was last reviewed, we should lower our confidence in decisions that depend on it.', '["provenance","positionality","confidence"]', '2026-06-06T11:45:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_008', 'recgdpwEI5hF07bUZ', 'decisions', 'The team agreed that high-risk service decisions need an evidence handover note before they move to implementation. The note should capture the decision, supporting findings, known gaps and the researcher confidence level.', '["handover","decision-rationale","confidence-threshold"]', '2026-06-06T15:25:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_009', 'recgdpwEI5hF07bUZ', 'procedures', 'We added a short pause before contacting participants whose circumstances may make participation burdensome. The pause gives the researcher time to review consent wording, support options and whether the invitation should be delayed.', '["consent","ethical-pacing","participant-burden"]', '2026-06-07T10:10:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_010', 'recgdpwEI5hF07bUZ', 'perceptions', 'The dashboard is useful when it shows what changed since the last visit. Researchers do not need another place to duplicate updates; they need a way to re-enter the project without reading every artefact again.', '["duplicate-updates","context-rebuilding","dashboard"]', '2026-06-07T14:55:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_011', 'recgdpwEI5hF07bUZ', 'introspections', 'The emotional labour of holding uncertainty for a project team is becoming more visible. Researchers are being asked for certainty before the evidence is ready, and the platform needs to legitimise saying that confidence is not yet high enough.', '["emotional-labour","uncertainty","confidence-threshold"]', '2026-06-08T09:50:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2'),
('d1tp1_journal_012', 'recgdpwEI5hF07bUZ', 'decisions', 'We agreed to show code co-occurrence as a prompt for interpretation, not as proof of a relationship. The graph should help researchers notice patterns, then return to journal entries and memos to check the meaning.', '["co-occurrence","analysis-practice","interpretation"]', '2026-06-08T16:35:00.000Z', 'd04ab32e-6756-408e-a649-6859dd0079f2')
